  ('heelevel3-d0d1b9a2-moex-00156', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-ddeb88e9', 'sub-heelevel3-d0d1b9a2-03', NULL, 'single_choice', '近年來，中央政府編列特別預算來推動各項重大基礎建設，依預算法規定，下列那些屬於特別預', '["重大災變", "不定期之重大政事", "國防 緊急設施", "國家經濟重大變故  ⑤所辦事業因重大事故經費超過法定預算時"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "decf00fa6f3c", "answer_pdf_sha1": "9c6129bcb5e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計審計法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00157', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-ddeb88e9', 'sub-heelevel3-d0d1b9a2-03', NULL, 'single_choice', '預算編製規範涉及行政與民意監督機關之關係，亦涉及中央機關與地方政府機關之運作，依我國 憲法、預算法對於中央政府及地方制度法對於直轄市政府之下年度總預算案，分別依序規定應於 會計年度開始幾個月前送達民意監督機關？', '["均規定四個月前", "三個月前、四個月前、四個月前", "三個月前、四個月前、三個月前", "均規定三個月前"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "decf00fa6f3c", "answer_pdf_sha1": "9c6129bcb5e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計審計法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00158', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-ddeb88e9', 'sub-heelevel3-d0d1b9a2-03', NULL, 'single_choice', '依決算法規定決算之編造內容，下列敘述何者錯誤？', '["機關別之單位決算，由各該單位機關編造之", "特種基金之單位決算，由各該基金之主管機關依前項規定辦理之", "機關之改組、變更致預算分立或基金先合併而後分立者，其未分立期間之決算，由原機關或原 基金主管機關編造", "特別預算之收支，應於執行期滿後，併年度總決算辦理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "decf00fa6f3c", "answer_pdf_sha1": "9c6129bcb5e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計審計法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00159', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-ddeb88e9', 'sub-heelevel3-d0d1b9a2-03', NULL, 'single_choice', '依預算法第16條規定，預算分成總預算、單位預算、單位預算之分預算、附屬單位預算、附屬單 位預算之分預算，其預算編製更結合基金分類方式辦理，相輔相成，其相互關係之敘述，下列何 者錯誤？', '["總預算、單位預算中，均為普通基金預算", "單位預算應編入總預算者，在歲入為來源別科目及其數額，在歲出為計畫或業務別科目及其數額", "總預算歲入、歲出應以各單位預算之歲入、歲出總額及附屬單位預算歲入、歲出之應編入部分， 彙整編成之", "特種基金以單位預算方式編列，應於總預算中編列全部歲入、歲出之基金之預算"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "decf00fa6f3c", "answer_pdf_sha1": "9c6129bcb5e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計審計法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00160', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-ddeb88e9', 'sub-heelevel3-d0d1b9a2-03', NULL, 'single_choice', '政府預算案之編造須經過籌劃、編造與審議之過程，並於年度開始9個月前，訂定下年度之施政 方針，俟預算成立執行時，往往碰到社會、經濟等因素大幅變化，為保留預算執行彈性，故於預 算法內訂有預備金機制，有關預備金相關規定，下列敘述何者錯誤？', '["預備金動支均須報經行政院核定後始得動支", "各機關動支預備金，其每筆數額超過五千萬元者，應先送立法院備查。但因緊急災害動支者， 不在此限", "立法院審議刪除或刪減之預算項目及金額，不得動支預備金。但法定經費或經立法院同意者， 不在此限", "行政院核准動支第二預備金及其歸屬科目金額之調整，事後由行政院編具動支數額表，送請立 法院審議"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "decf00fa6f3c", "answer_pdf_sha1": "9c6129bcb5e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計審計法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00161', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-ddeb88e9', 'sub-heelevel3-d0d1b9a2-03', NULL, 'single_choice', '依預算法第13條規定，政府歲入與歲出、債務之舉借與以前年度歲計賸餘之移用及債務之償還， 均應編入其預算；然其編製歲入、歲出所產生之差短，可透由下列何者予以撥補？', '["賸餘繳庫", "未分配盈餘", "賒借", "盈虧撥補"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "decf00fa6f3c", "answer_pdf_sha1": "9c6129bcb5e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計審計法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00162', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-ddeb88e9', 'sub-heelevel3-d0d1b9a2-03', NULL, 'single_choice', '依預算法第47條規定，中央政府總預算案與附屬單位預算及其綜計表，經行政院會議決定後，交 由中央主計機關彙編，為便於中央主計機關預算之籌編，預算法規定授權由中央主計機關定之， 下列何者非屬其授權範圍？', '["擬訂下年度預算編製辦法", "歲入來源別科目之名稱及其分類", "歲出政事別、計畫或業務別與用途別科目之名稱及其分類", "預算書表格式"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "decf00fa6f3c", "answer_pdf_sha1": "9c6129bcb5e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計審計法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00163', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-ddeb88e9', 'sub-heelevel3-d0d1b9a2-03', NULL, 'single_choice', '預算之籌劃、編造、審議、成立及執行，均有規定之期程，各級政府預算案之審議，如未能依預 算法及地方制度法規定之期限完成審議時，其相關補救措施及預算執行規定之敘述，下列何者錯 誤？', '["收入部分暫依上年度標準及實際發生數，覈實收入", "地方政府得就原提總預算案未審議完成部分，報請行政院、內政部、縣政府邀集各有關機關協商", "地方政府報請協商時，逾期未決定者，由地方政府逕為執行之", "立法院在審議當年度預算中已初步刪減之項目不得動支，但履行法定義務支出之項目除外"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "decf00fa6f3c", "answer_pdf_sha1": "9c6129bcb5e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計審計法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00164', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-ddeb88e9', 'sub-heelevel3-d0d1b9a2-03', NULL, 'single_choice', '隨著民主政治發展，預算成為人民藉以監督政府重要之工具，並藉由預算之審議，達成行使監督 政府之責，以杜絕政府浮收濫用及擴張權力，故預算法對於政府財政收支及預算基本處理原則均 有其規範，其規範內容下列敘述何者錯誤？', '["政府徵收賦稅、規費及因實施管制所發生之收入，或其他有強制性之收入，應先經本法所定預 算程序。但法律另有規定者，不在此限", "政府不得於預算所定外，動用公款、處分公有財物或為投資之行為", "政府大宗動產、不動產之買賣或交換，均須依據本法所定預算程序為之", "政府非依法律，不得於其預算外增加債務與發行國庫券"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "decf00fa6f3c", "answer_pdf_sha1": "9c6129bcb5e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計審計法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL)
